import { useState } from "react";
import { useData } from "../contexts/DataContext";
import { useAuth } from "../contexts/AuthContext";
import { Button } from "../components/ui/button";
import { Input } from "../components/ui/input";
import { Save, LogOut, User, Pencil } from "lucide-react";
import { toast } from "sonner";
import { useNavigate } from "react-router-dom";

export default function Profil() {
  const { profile, setProfile } = useData();
  const { logout } = useAuth();
  const navigate = useNavigate();
  const [form, setForm] = useState(profile);
  const set = (k, v) => setForm({ ...form, [k]: v });

  const handleSave = () => {
    setProfile(form);
    toast.success("Profil berhasil diperbarui");
  };

  const handleLogout = () => {
    logout();
    navigate("/login");
  };

  return (
    <div className="min-h-screen bg-gray-50" data-testid="profil-page">
      {/* Header Section */}
      <div className="bg-white border-b border-gray-100 px-10 py-8">
        <div className="max-w-4xl flex items-center gap-6">
          {/* Avatar */}
          <div className="relative">
            <div className="w-24 h-24 rounded-xl overflow-hidden bg-[#1e2d3d] flex items-center justify-center">
              <svg viewBox="0 0 100 100" className="w-full h-full" fill="none">
                <rect width="100" height="100" fill="#1e2d3d" />
                <circle cx="50" cy="38" r="18" fill="#e8a87c" />
                <ellipse cx="50" cy="80" rx="28" ry="20" fill="#5b8fa8" />
                <circle cx="50" cy="38" r="14" fill="#d4956b" />
                <path d="M36 42 Q50 55 64 42" stroke="#c17d4e" strokeWidth="2" fill="none" />
                <rect x="30" y="56" width="40" height="30" rx="4" fill="#5b8fa8" />
              </svg>
            </div>
            <button className="absolute -bottom-2 -right-2 w-8 h-8 bg-[#F59E0B] rounded-lg flex items-center justify-center shadow-md hover:bg-[#d97706] transition-colors">
              <Pencil className="w-3.5 h-3.5 text-white" />
            </button>
          </div>

          {/* Identity */}
          <div>
            <p className="text-xs tracking-[0.18em] uppercase text-gray-400 font-semibold mb-1">
              System Administrator
            </p>
            <h1 className="text-4xl font-black text-gray-900 leading-tight">
              {form.name?.split(" ")[0] || "Zuhri"}
            </h1>
            <p className="text-gray-500 mt-1">{form.role || "Head of Operations & Logistics Analytics"}</p>
          </div>
        </div>
      </div>

      {/* Profile Info Section */}
      <div className="max-w-4xl mx-auto px-10 py-8">
        <div className="bg-white rounded-xl shadow-sm border border-gray-100 p-8">
          {/* Section Title */}
          <div className="flex items-center gap-2 mb-8">
            <User className="w-5 h-5 text-[#F59E0B]" />
            <h2 className="text-lg font-bold text-gray-900">Informasi Profil</h2>
          </div>

          {/* Fields Grid */}
          <div className="grid grid-cols-2 gap-x-12 gap-y-7">
            <ProfileField
              label="Nama Lengkap"
              testId="profile-name"
              value={form.name}
              onChange={(v) => set("name", v)}
            />
            <ProfileField
              label="Alamat Email"
              testId="profile-email"
              value={form.email}
              onChange={(v) => set("email", v)}
            />
            <ProfileField
              label="Nomor Telepon"
              testId="profile-phone"
              value={form.phone}
              onChange={(v) => set("phone", v)}
            />
            <ProfileField
              label="Jabatan / Role"
              testId="profile-role"
              value={form.role}
              onChange={(v) => set("role", v)}
            />
            <ProfileField
              label="Cabang"
              testId="profile-branch"
              value={form.branch}
              onChange={(v) => set("branch", v)}
            />
            <ProfileField
              label="Tanggal Bergabung"
              testId="profile-joindate"
              value={form.joinDate}
              onChange={(v) => set("joinDate", v)}
            />
          </div>

          {/* Actions */}
          <div className="mt-10 flex items-center justify-between pt-6 border-t border-gray-100">
            <Button
              variant="outline"
              onClick={handleLogout}
              data-testid="profile-logout"
              className="h-10 px-5 text-red-500 border-red-200 hover:bg-red-50 hover:text-red-600 text-sm"
            >
              <LogOut className="w-4 h-4 mr-2" /> Keluar
            </Button>
            <Button
              onClick={handleSave}
              data-testid="save-profile-btn"
              className="mpl-btn-primary h-10 px-6 text-sm"
            >
              <Save className="w-4 h-4 mr-2" /> Simpan Perubahan
            </Button>
          </div>
        </div>
      </div>
    </div>
  );
}

function ProfileField({ label, value, onChange, testId }) {
  return (
    <div className="border-b border-gray-200 pb-4">
      <p className="text-[10px] tracking-[0.15em] uppercase text-gray-400 font-semibold mb-2">
        {label}
      </p>
      <input
        data-testid={testId}
        value={value || ""}
        onChange={(e) => onChange(e.target.value)}
        className="w-full text-sm font-semibold text-gray-900 bg-transparent outline-none border-none focus:ring-0 p-0 placeholder-gray-300"
      />
    </div>
  );
}
